THOUGHT: The crash occurs in FunctionAttrs.cpp when building access ranges for memset with a large offset that causes wrap-around. A ConstantRange with Lower >= Upper (a wrapped set) is being inserted into ConstantRangeList, which asserts that NewRange.getLower().slt(NewRange.getUpper()). The fix is to avoid creating wrapped ConstantRanges for byte access intervals. In getArgumentAccessInfo, when computing [Offset, Offset+Size), we should split wrapped ranges into two non-wrapping ranges or clamp the end using saturating arithmetic to ensure Lower < Upper. I will update FunctionAttrs.cpp to handle add-with-wrap by either splitting or by guarding against wrapped ranges, and ensure ConstantRangeList receives only non-wrapped ranges.

```bash
ls -la && echo "Searching relevant files..." && grep -Rn "ConstantRangeList" -n llvm/lib | sed -n '1,200p' && nl -ba llvm/lib/IR/ConstantRangeList.cpp | sed -n '1,200p' && echo "Open FunctionAttrs parts..." && grep -Rn "getArgumentAccessInfo" llvm/lib/Transforms/IPO/FunctionAttrs.cpp && nl -ba llvm/lib/Transforms/IPO/FunctionAttrs.cpp | sed -n '650,840p' && echo "Apply patch to handle wrapped ranges in getArgumentAccessInfo..." && python3 - <<'PY'
import io,sys,re,os, textwrap, json
path = "llvm/lib/Transforms/IPO/FunctionAttrs.cpp"
with open(path,'r') as f:
    s=f.read()
# We'll inject logic around where ConstantRange is created for memory intrinsics (memset/memcpy).
# Locate getArgumentAccessInfo and find handling that inserts ranges into ConstantRangeList.
start = s.find("static AccessInfo getArgumentAccessInfo(")
if start==-1:
    print("Function not found", file=sys.stderr); sys.exit(1)
# We'll search forward for places that construct ConstantRange with Offset and Size.
# Heuristically, search for "ConstantRange(" within that function region up to next "static".
end = s.find("\nstatic ", start+1)
if end==-1: end = len(s)
region = s[start:end]
# Pattern: NewRanges.insert(ConstantRange(Lower, Upper)) or CRList.insert(CR)
# We will define a small helper lambda to insert non-wrapped ranges.
insert_helper_decl = """
  auto insertNonWrappedRange = [&](ConstantRangeList &CRL, const APInt &Lower, const APInt &Upper) {
    // If Lower < Upper (signed), insert directly; if Lower == Upper it's empty; if wrapped, split.
    if (Lower.slt(Upper)) {
      CRL.insert(ConstantRange(Lower, Upper));
      return;
    }
    if (Lower == Upper) {
      // Empty range; nothing to insert.
      return;
    }
    // Wrapped: split into [Lower, Max] and [Min, Upper], using full bitwidth.
    unsigned BW = Lower.getBitWidth();
    APInt Min = APInt::getSignedMinValue(BW);
    APInt Max = APInt::getSignedMaxValue(BW) + 1; // exclusive upper for ConstantRange
    // Insert [Lower, Min+2^BW) -> model as [Lower, MaxExclusive) by using unsigned full range upper.
    // However ConstantRange uses half-open [Lower, Upper) with APInt; to represent [Lower, 2^BW),
    // Upper should be 0. But ConstantRangeList::insert asserts slt, so avoid that by clamping to Max.
    // Instead, split into [Lower, Max] and [Min, Upper).
    APInt MaxExclusive = APInt::getSignedMaxValue(BW) + 1; // one past max signed
    // First: [Lower, MaxExclusive)
    if (Lower.slt(MaxExclusive))
      CRL.insert(ConstantRange(Lower, MaxExclusive));
    // Second: [Min, Upper)
    if (Min.slt(Upper))
      CRL.insert(ConstantRange(Min, Upper));
  };
"""
# Insert the helper after function start brace.
func_body_start = region.find("{", region.find("getArgumentAccessInfo")) + 1
new_region = region[:func_body_start] + insert_helper_decl + region[func_body_start:]
# Now replace direct CRList.insert(ConstantRange(L, U)) inside region with calls to helper.
# We look for patterns of "CRList.insert(ConstantRange(" with two APInt args.
new_region = re.sub(r'(\b[A-Za-z_][A-Za-z0-9_]*\s*&\s*)?([A-Za-z_][A-Za-z0-9_]*)\.insert\s*\(\s*ConstantRange\s*\(\s*([^,]+)\s*,\s*([^)]+)\)\s*\)\s*;',
                    r'insertNonWrappedRange(\2, \3, \4);', new_region)
# Put back
news = s[:start] + new_region + s[func_body_start+len(insert_helper_decl):end] + s[end:]
if news==s:
    # If not matched, try a targeted insertion and replace specific known locations by scanning for "ConstantRangeList".
    pass
with open(path,'w') as f:
    f.write(news)
print("Patched FunctionAttrs.cpp")
PY
 && echo "Build and run reproducer..." && ninja -C build/llvm-build/140345 opt -j2 && cat >/tmp/test.ll <<'LL' && build/llvm-build/140345/bin/opt -passes=function-attrs -S /tmp/test.ll
define void @memset_large_offset_nonzero_size(ptr %dst) {
  %offset = getelementptr inbounds i8, ptr %dst, i64 9223372036854775805
  call void @llvm.memset.p0.i64(ptr %offset, i8 0, i64 3, i1 false)
  ret void
}

; Function Attrs: nocallback nofree nounwind willreturn memory(argmem: write)
declare void @llvm.memset.p0.i64(ptr writeonly captures(none), i8, i64, i1 immarg) #0

attributes #0 = { nocallback nofree nounwind willreturn memory(argmem: write) }
LL
 && echo "Run full submit-patch to validate..." && submit-patch
```

