THOUGHT: The crash happens because FunctionAttrs builds ConstantRange intervals that wrap around when adding large offsets (e.g., from GEP) and then inserts them into ConstantRangeList, which asserts that ranges are non-wrapped with signed Lower < Upper. A safe and conservative fix is to avoid inserting wrapped or empty ranges. I’ll add a small helper in getArgumentAccessInfo to only insert ranges when Lower.slt(Upper), and apply it to both the memory-intrinsic case and the Attribute::Initializes offsetting case.

```bash
applypatch << 'PATCH'
*** Begin Patch
*** Update File: llvm/lib/Transforms/IPO/FunctionAttrs.cpp
@@
 static AccessInfo getArgumentAccessInfo(const Instruction *I,
                                         const ArgumentUse &ArgUse,
                                         const DataLayout &DL) {
+  // Helper to insert only non-wrapped, non-empty signed ranges.
+  auto insertIfNonWrapped = [](ConstantRangeList &CRL, const APInt &L,
+                               const APInt &U) {
+    if (L.slt(U))
+      CRL.insert(ConstantRange(L, U));
+  };
@@
   if (const auto *MI = dyn_cast<AnyMemSetInst>(I)) {
     if (ArgUse.Offset) {
       // memset writes a contiguous range [Offset, Offset + Size)
       ConstantRangeList AccessRanges;
-      AccessRanges.insert(ConstantRange(
-          APInt(64, *ArgUse.Offset, /*isSigned*/ true),
-          APInt(64, *ArgUse.Offset + MI->getLength().value_or(0), /*isSigned*/ true)));
+      // Compute bounds as signed APInt and avoid inserting wrapped ranges.
+      unsigned BW = 64;
+      APInt Off(BW, static_cast<uint64_t>(*ArgUse.Offset), /*isSigned*/ true);
+      uint64_t SizeVal = MI->getLength().value_or(0);
+      APInt End = Off + APInt(BW, SizeVal, /*isSigned*/ false);
+      insertIfNonWrapped(AccessRanges, Off, End);
       return {ArgumentAccessInfo::AccessType::Write, AccessRanges};
     }
   }
@@
     bool IsInitialize = CB->paramHasAttr(ArgNo, Attribute::Initializes);
     if (IsInitialize && ArgUse.Offset) {
       // Argument is a Write when parameter is writeonly/readnone
       // and nocapture. Otherwise, it's a WriteWithSideEffect.
       auto Access = CB->onlyWritesMemory(ArgNo) && CB->doesNotCapture(ArgNo)
                         ? ArgumentAccessInfo::AccessType::Write
                         : ArgumentAccessInfo::AccessType::WriteWithSideEffect;
       ConstantRangeList AccessRanges;
       Attribute Attr = CB->getParamAttr(ArgNo, Attribute::Initializes);
       ConstantRangeList CBCRL = Attr.getValueAsConstantRangeList();
-      for (ConstantRange &CR : CBCRL)
-        AccessRanges.insert(ConstantRange(CR.getLower() + *ArgUse.Offset,
-                                          CR.getUpper() + *ArgUse.Offset));
+      // Add the GEP-derived offset; avoid inserting wrapped ranges.
+      // Use the bitwidth of the existing ranges to build the offset APInt.
+      for (ConstantRange &CR : CBCRL) {
+        unsigned BW = CR.getLower().getBitWidth();
+        APInt Off(BW, static_cast<uint64_t>(*ArgUse.Offset), /*isSigned*/ true);
+        APInt L = CR.getLower() + Off;
+        APInt U = CR.getUpper() + Off;
+        insertIfNonWrapped(AccessRanges, L, U);
+      }
       return {Access, AccessRanges};
     }
*** End Patch
PATCH
